import { FeatureCollection } from 'geojson';

export const mergeFeatureCollections = (features: FeatureCollection[]) =>
  features.reduce(
    (accumulator, currentValue) => {
      accumulator.features = accumulator.features.concat(currentValue.features);

      return accumulator;
    },
    {
      type: 'FeatureCollection',
      features: [],
    },
  );
